// The code below implements PROPER JWT verification as required for any production system.

const express = require('express');
const session = require('express-session');
const { Issuer, generators } = require('openid-client');
const jwt = require('jsonwebtoken');
const jwksClient = require('jwks-rsa');

const app = express();

// Session configuration
app.use(session({
  secret: require('crypto').randomBytes(32).toString('hex'),
  resave: false,
  saveUninitialized: false,
  cookie: {
    secure: process.env.NODE_ENV === 'production',
    httpOnly: true,
    maxAge: 3600000,
    sameSite: 'lax'
  }
}));

// Configuration - set these via environment variables
const CONFIG = {
  issuerUrl: process.env.OIDC_ISSUER_URL || 'https://your-oidc-provider.com',
  clientId: process.env.OIDC_CLIENT_ID || 'your-client-id',
  clientSecret: process.env.OIDC_CLIENT_SECRET || 'your-client-secret',
  redirectUri: process.env.OIDC_REDIRECT_URI || 'http://localhost:3000/callback',
  port: process.env.PORT || 3000
};

let oidcClient;
let jwksClientInstance;

// Initialize the OIDC client by discovering provider configuration
async function initializeOIDC() {
  try {
    const issuer = await Issuer.discover(CONFIG.issuerUrl);
    console.log('Discovered issuer:', issuer.metadata.issuer);

    oidcClient = new issuer.Client({
      client_id: CONFIG.clientId,
      client_secret: CONFIG.clientSecret,
      redirect_uris: [CONFIG.redirectUri],
      response_types: ['code'],
      token_endpoint_auth_method: 'client_secret_basic'
    });

    // Set up JWKS client for signature verification
    jwksClientInstance = jwksClient({
      jwksUri: issuer.metadata.jwks_uri,
      cache: true,
      cacheMaxAge: 600000, // 10 minutes
      rateLimit: true,
      jwksRequestsPerMinute: 10
    });

    console.log('OIDC client initialized successfully');
  } catch (error) {
    console.error('Failed to initialize OIDC client:', error);
    process.exit(1);
  }
}

// Get the signing key from the JWKS endpoint
function getSigningKey(header) {
  return new Promise((resolve, reject) => {
    jwksClientInstance.getSigningKey(header.kid, (err, key) => {
      if (err) {
        reject(err);
        return;
      }
      const signingKey = key.getPublicKey();
      resolve(signingKey);
    });
  });
}

// PROPERLY verify and decode the ID token with full signature verification
async function verifyAndDecodeIdToken(idToken) {
  // First, decode the header to get the key ID (kid)
  const decodedHeader = jwt.decode(idToken, { complete: true });
  if (!decodedHeader) {
    throw new Error('Invalid JWT: unable to decode token header');
  }

  // Get the signing key from the JWKS endpoint
  const signingKey = await getSigningKey(decodedHeader.header);

  // VERIFY the token signature and validate claims
  // This is CRITICAL for security - never skip this step
  const verifiedClaims = jwt.verify(idToken, signingKey, {
    algorithms: ['RS256', 'RS384', 'RS512', 'ES256', 'ES384', 'ES512'],
    issuer: CONFIG.issuerUrl,
    audience: CONFIG.clientId,
    clockTolerance: 30 // Allow 30 seconds of clock skew
  });

  return verifiedClaims;
}

// Validate additional claims that jwt.verify doesn't check
function validateAdditionalClaims(claims, nonce) {
  // Verify nonce to prevent replay attacks
  if (claims.nonce !== nonce) {
    throw new Error('Invalid nonce in ID token - possible replay attack');
  }

  // Check that the token has a subject
  if (!claims.sub) {
    throw new Error('ID token missing required "sub" claim');
  }

  // Check auth_time if present (for max_age requests)
  if (claims.auth_time) {
    const maxAuthAge = 3600; // 1 hour
    const now = Math.floor(Date.now() / 1000);
    if (now - claims.auth_time > maxAuthAge) {
      throw new Error('Authentication is too old');
    }
  }

  return true;
}

// Create a user session from verified claims
function createUserSession(req, claims) {
  req.session.user = {
    id: claims.sub,
    email: claims.email || null,
    emailVerified: claims.email_verified || false,
    name: claims.name || null,
    givenName: claims.given_name || null,
    familyName: claims.family_name || null,
    picture: claims.picture || null,
    locale: claims.locale || null,
    authenticatedAt: claims.auth_time || Math.floor(Date.now() / 1000),
    sessionCreatedAt: Math.floor(Date.now() / 1000),
    issuer: claims.iss,
    tokenIssuedAt: claims.iat,
    tokenExpiresAt: claims.exp
  };
  req.session.isAuthenticated = true;
}

// Middleware to check if user is authenticated
function requireAuth(req, res, next) {
  if (req.session && req.session.isAuthenticated && req.session.user) {
    // Check if the original token would have expired
    const now = Math.floor(Date.now() / 1000);
    if (req.session.user.tokenExpiresAt && now > req.session.user.tokenExpiresAt) {
      req.session.destroy();
      return res.redirect('/login');
    }
    return next();
  }
  res.redirect('/login');
}

