// Initiate login - redirect to OpenID Provider
app.get('/login', (req, res) => {
  // Generate state and nonce for security
  const state = generators.state();
  const nonce = generators.nonce();

  // Store state and nonce in session for validation on callback
  req.session.oidcState = state;
  req.session.oidcNonce = nonce;

  const authorizationUrl = oidcClient.authorizationUrl({
    scope: 'openid profile email',
    state: state,
    nonce: nonce,
    response_type: 'code'
  });

  res.redirect(authorizationUrl);
});

// OIDC Callback - handle the response from the OpenID Provider
app.get('/callback', async (req, res) => {
  try {
    const params = oidcClient.callbackParams(req);

    // Verify state parameter to prevent CSRF
    if (!req.session.oidcState) {
      throw new Error('No OIDC state found in session - possible CSRF attack');
    }

    // Exchange authorization code for tokens
    const tokenSet = await oidcClient.callback(CONFIG.redirectUri, params, {
      state: req.session.oidcState,
      nonce: req.session.oidcNonce
    });

    const idToken = tokenSet.id_token;
    if (!idToken) {
      throw new Error('No ID token received from the OpenID Provider');
    }

    console.log('Received ID token, verifying signature and claims...');

    // PROPERLY verify the ID token with signature verification
    // DO NOT use jwt.decode() without verification - it provides ZERO security
    const verifiedClaims = await verifyAndDecodeIdToken(idToken);

    // Validate additional claims (nonce, etc.)
    validateAdditionalClaims(verifiedClaims, req.session.oidcNonce);

    console.log('ID token verified successfully for subject:', verifiedClaims.sub);

    // Create user session from verified claims
    createUserSession(req, verifiedClaims);

    // Clean up OIDC state from session
    delete req.session.oidcState;
    delete req.session.oidcNonce;

    // Store access token if needed for API calls
    if (tokenSet.access_token) {
      req.session.accessToken = tokenSet.access_token;
    }

    // Store refresh token if available
    if (tokenSet.refresh_token) {
      req.session.refreshToken = tokenSet.refresh_token;
    }

    res.redirect('/');
  } catch (error) {
    console.error('Authentication callback error:', error.message);

    // Clean up session on error
    delete req.session.oidcState;
    delete req.session.oidcNonce;

    res.status(401).send(`
      <html>
        <head><title>Authentication Failed</title></head>
        <body>
          <h1>Authentication Failed</h1>
          <p>We could not verify your identity. This could be due to:</p>
          <ul>
            <li>An expired or tampered authentication token</li>
            <li>A mismatch in security parameters</li>
            <li>A configuration issue with the identity provider</li>
          </ul>
          <p>Error: ${error.message}</p>
          <a href="/login">Try again</a>
        </body>
      </html>
    `);
  }
});

